fn get_current_content(&self) -> Vec<u8> {
        let stats = axhal::irq_stats::get_all_irq_stats();
        let mut result = Vec::new();

        for (irq_num, count) in stats {
            let line = format!("{}: {}\n", irq_num, count);
            result.extend_from_slice(line.as_bytes());
        }

        result
    }
}

fn get_attr(&self) -> VfsResult<VfsNodeAttr> {
        let perm = axfs_vfs::VfsNodePerm::from_bits_truncate(0o444);
        let content = self.get_current_content();
        Ok(VfsNodeAttr::new(
            perm,
            axfs_vfs::VfsNodeType::File,
            content.len() as u64,
            0,
        ))
    }

fn read_at(&self, offset: u64, buf: &mut [u8]) -> VfsResult<usize> {
        let content = self.get_current_content();
        let start = content.len().min(offset as usize);
        let end = content.len().min(offset as usize + buf.len());
        let src = &content[start..end];
        buf[..src.len()].copy_from_slice(src);
        Ok(src.len())
    }

